export interface WatermarkDetectionResult {
  x: number;
  y: number;
  width: number;
  height: number;
  confidence: number;
  backgroundColor: string; // Hex color code or "white"
  description: string;
}

export interface ProcessingStep {
  label: string;
  status: 'pending' | 'loading' | 'completed' | 'error';
}

export enum AppStatus {
  IDLE = 'IDLE',
  UPLOADING = 'UPLOADING',
  ANALYZING = 'ANALYZING',
  READY_TO_PROCESS = 'READY_TO_PROCESS',
  PROCESSING = 'PROCESSING',
  COMPLETED = 'COMPLETED'
}

import { GoogleGenAI, Type } from "@google/genai";
import { WatermarkDetectionResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export async function detectWatermark(imageBase64: string): Promise<WatermarkDetectionResult> {
  const model = 'gemini-3-flash-preview';

  const prompt = `
    Analyze the bottom-right corner of this PDF slide. 
    Identify the exact bounding box of any watermark, logo, or repetitive branding text. 
    The coordinates should be in percentages relative to the provided crop (0-100).
    Also identify the background color behind the watermark to help in patching.
    Return the result in JSON format.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { mimeType: 'image/jpeg', data: imageBase64 } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          x: { type: Type.NUMBER, description: "X coordinate of the top-left corner (0-100)" },
          y: { type: Type.NUMBER, description: "Y coordinate of the top-left corner (0-100)" },
          width: { type: Type.NUMBER, description: "Width of the watermark (0-100)" },
          height: { type: Type.NUMBER, description: "Height of the watermark (0-100)" },
          confidence: { type: Type.NUMBER, description: "Confidence score (0-1)" },
          backgroundColor: { type: Type.STRING, description: "Dominant background color (e.g., #FFFFFF)" },
          description: { type: Type.STRING, description: "Brief description of detected watermark" }
        },
        required: ["x", "y", "width", "height", "backgroundColor"]
      }
    }
  });

  try {
    const result = JSON.parse(response.text || '{}');
    return result as WatermarkDetectionResult;
  } catch (error) {
    console.error("Failed to parse Gemini response", error);
    throw new Error("Failed to detect watermark pattern automatically.");
  }
}

import { PDFDocument, rgb } from 'pdf-lib';

// Declare pdfjsLib globally since it's loaded in index.html
declare const pdfjsLib: any;

export async function getPdfThumbnail(file: File): Promise<{ dataUrl: string; width: number; height: number }> {
  const arrayBuffer = await file.arrayBuffer();
  const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
  const page = await pdf.getPage(1);
  const viewport = page.getViewport({ scale: 1.5 });

  const canvas = document.createElement('canvas');
  const context = canvas.getContext('2d');
  canvas.height = viewport.height;
  canvas.width = viewport.width;

  await page.render({ canvasContext: context, viewport }).promise;
  return {
    dataUrl: canvas.toDataURL('image/jpeg', 0.8),
    width: viewport.width,
    height: viewport.height
  };
}

export async function getBottomRightCrop(file: File): Promise<string> {
  const arrayBuffer = await file.arrayBuffer();
  const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
  const page = await pdf.getPage(1);

  // High scale for better detection
  const viewport = page.getViewport({ scale: 2.0 });

  const canvas = document.createElement('canvas');
  const context = canvas.getContext('2d')!;

  // Crop only the bottom right 30% of the page
  const cropW = viewport.width * 0.4;
  const cropH = viewport.height * 0.4;
  canvas.width = cropW;
  canvas.height = cropH;

  // We want to render the bottom right portion
  // transform: [scaleX, skewY, skewX, scaleY, translateX, translateY]
  // We offset the context to capture the bottom right
  context.translate(- (viewport.width - cropW), - (viewport.height - cropH));

  await page.render({ canvasContext: context, viewport }).promise;

  return canvas.toDataURL('image/jpeg', 0.9).split(',')[1];
}

function hexToRgb(hex: string) {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result ? {
    r: parseInt(result[1], 16) / 255,
    g: parseInt(result[2], 16) / 255,
    b: parseInt(result[3], 16) / 255
  } : { r: 1, g: 1, b: 1 };
}

export async function removeWatermarkFromPdf(
  file: File, 
  detection: { x: number; y: number; width: number; height: number; backgroundColor: string },
  onProgress: (p: number) => void
): Promise<Uint8Array> {
  const existingPdfBytes = await file.arrayBuffer();
  const pdfDoc = await PDFDocument.load(existingPdfBytes);
  const pages = pdfDoc.getPages();
  const { r, g, b } = hexToRgb(detection.backgroundColor);

  for (let i = 0; i < pages.length; i++) {
    const page = pages[i];
    const { width, height } = page.getSize();

    // Map the relative detection coordinates back to PDF coordinates
    // Note: detection was on a 40% crop of the bottom-right.
    // Let's refine the logic:
    // Crop area starts at: X = 60%, Y = 60%
    // Within that 40% crop, Gemini gives us x, y (0-100)

    const cropStartX = width * 0.6;
    const cropStartY = height * 0.6; // Bottom is 0 in PDF coordinates, but rendering was top-down.

    // PDF coordinates: (0,0) is bottom-left.
    // Rendering coordinates: (0,0) is top-left.

    // Convert relative crop coordinates to absolute page coordinates
    const patchWidth = (detection.width / 100) * (width * 0.4);
    const patchHeight = (detection.height / 100) * (height * 0.4);

    // X in crop: 0 is left edge of crop (which is 60% of page width)
    const patchX = cropStartX + (detection.x / 100) * (width * 0.4);

    // Y in crop: 0 is top edge of crop (which is 40% from bottom of page)
    // In PDF: y=0 is bottom. Top of crop is at height * 0.4.
    const cropTopInPdf = height * 0.4;
    const patchY = cropTopInPdf - (detection.y / 100) * (height * 0.4) - patchHeight;

    page.drawRectangle({
      x: patchX,
      y: patchY,
      width: patchWidth,
      height: patchHeight,
      color: rgb(r, g, b),
      borderWidth: 0,
    });

    onProgress(Math.round(((i + 1) / pages.length) * 100));
  }

  return await pdfDoc.save();
}

import React, { useState, useCallback, useRef } from 'react';
import { 
  FileUp, 
  Trash2, 
  CheckCircle2, 
  Download, 
  Zap, 
  Loader2, 
  AlertCircle,
  FileText,
  MousePointer2,
  ScanSearch
} from 'lucide-react';
import { AppStatus, WatermarkDetectionResult } from './types';
import { getPdfThumbnail, getBottomRightCrop, removeWatermarkFromPdf } from './services/pdfService';
import { detectWatermark } from './services/geminiService';

export default function App() {
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [file, setFile] = useState<File | null>(null);
  const [thumbnail, setThumbnail] = useState<string | null>(null);
  const [detection, setDetection] = useState<WatermarkDetectionResult | null>(null);
  const [progress, setProgress] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const [processedPdf, setProcessedPdf] = useState<Uint8Array | null>(null);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (!selectedFile || selectedFile.type !== 'application/pdf') {
      setError("Please select a valid PDF file.");
      return;
    }
    reset();
    setFile(selectedFile);
    setStatus(AppStatus.UPLOADING);

    try {
      const { dataUrl } = await getPdfThumbnail(selectedFile);
      setThumbnail(dataUrl);
      setStatus(AppStatus.ANALYZING);

      // Auto-detect watermark with Gemini
      const cropBase64 = await getBottomRightCrop(selectedFile);
      const result = await detectWatermark(cropBase64);
      setDetection(result);
      setStatus(AppStatus.READY_TO_PROCESS);
    } catch (err: any) {
      setError(err.message || "An error occurred during analysis.");
      setStatus(AppStatus.IDLE);
    }
  };

  const startProcessing = async () => {
    if (!file || !detection) return;
    setStatus(AppStatus.PROCESSING);
    setProgress(0);

    try {
      const result = await removeWatermarkFromPdf(file, detection, (p) => setProgress(p));
      setProcessedPdf(result);
      setStatus(AppStatus.COMPLETED);
    } catch (err: any) {
      setError(err.message || "Failed to process PDF.");
      setStatus(AppStatus.READY_TO_PROCESS);
    }
  };

  const downloadResult = () => {
    if (!processedPdf || !file) return;
    const blob = new Blob([processedPdf], { type: 'application/pdf' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `cleaned_${file.name}`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const reset = () => {
    setFile(null);
    setThumbnail(null);
    setDetection(null);
    setProcessedPdf(null);
    setProgress(0);
    setError(null);
    setStatus(AppStatus.IDLE);
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans text-slate-900">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2">
            <div className="bg-indigo-600 p-2 rounded-lg">
              <Zap className="text-white w-5 h-5" />
            </div>
            <h1 className="text-xl font-bold tracking-tight bg-gradient-to-r from-indigo-600 to-violet-600 bg-clip-text text-transparent">
              PDF Watermark Remover Pro
            </h1>
          </div>
          {status !== AppStatus.IDLE && (
            <button 
              onClick={reset}
              className="text-slate-500 hover:text-red-600 transition-colors p-2 rounded-full hover:bg-red-50"
            >
              <Trash2 className="w-5 h-5" />
            </button>
          )}
        </div>
      </header>

      <main className="max-w-4xl mx-auto px-4 py-12">
        {/* Error Alert */}
        {error && (
          <div className="mb-8 p-4 bg-red-50 border border-red-200 rounded-xl flex items-center gap-3 text-red-700">
            <AlertCircle className="w-5 h-5 flex-shrink-0" />
            <p className="font-medium">{error}</p>
          </div>
        )}

        {/* Upload State */}
        {status === AppStatus.IDLE && (
          <div className="flex flex-col items-center">
            <div 
              onClick={() => fileInputRef.current?.click()}
              className="w-full max-w-xl aspect-[16/10] bg-white border-2 border-dashed border-slate-300 rounded-3xl flex flex-col items-center justify-center gap-4 cursor-pointer hover:border-indigo-400 hover:bg-indigo-50/30 transition-all group"
            >
              <div className="bg-indigo-100 p-6 rounded-2xl group-hover:scale-110 transition-transform">
                <FileUp className="w-12 h-12 text-indigo-600" />
              </div>
              <div className="text-center">
                <p className="text-xl font-semibold text-slate-800">Drop your PDF here</p>
                <p className="text-slate-500 mt-1">or click to browse from computer</p>
              </div>
              <input 
                type="file" 
                ref={fileInputRef} 
                onChange={handleFileChange} 
                className="hidden" 
                accept=".pdf"
              />
            </div>
            <p className="mt-8 text-slate-400 text-sm max-w-sm text-center">
              Works best for presentation slides with repeating watermarks in the bottom-right corner.
            </p>
          </div>
        )}

        {/* Processing/Analysis View */}
        {(status !== AppStatus.IDLE) && (
          <div className="grid md:grid-cols-2 gap-8 items-start">
            {/* Left: Preview */}
            <div className="space-y-4">
              <h2 className="text-lg font-semibold flex items-center gap-2">
                <FileText className="w-5 h-5 text-indigo-500" />
                Original Preview
              </h2>
              <div className="relative aspect-[4/3] bg-white border border-slate-200 rounded-2xl shadow-xl overflow-hidden group">
                {thumbnail ? (
                  <>
                    <img src={thumbnail} className="w-full h-full object-contain" alt="PDF Preview" />
                    {detection && (
                      <div 
                        className="absolute border-2 border-indigo-500 bg-indigo-500/10 z-10 animate-pulse"
                        style={{
                          left: `${60 + (detection.x * 0.4)}%`,
                          top: `${60 + (detection.y * 0.4)}%`,
                          width: `${detection.width * 0.4}%`,
                          height: `${detection.height * 0.4}%`,
                        }}
                      >
                        <div className="absolute -top-6 left-0 bg-indigo-600 text-white text-[10px] px-1.5 py-0.5 rounded shadow-sm whitespace-nowrap">
                          Detected Watermark Area
                        </div>
                      </div>
                    )}
                  </>
                ) : (
                  <div className="w-full h-full flex items-center justify-center bg-slate-100">
                    <Loader2 className="w-8 h-8 animate-spin text-slate-300" />
                  </div>
                )}
              </div>
              <p className="text-sm text-slate-500 italic">
                {file?.name} • {(file?.size ? file.size / (1024 * 1024) : 0).toFixed(2)} MB
              </p>
            </div>

            {/* Right: Controls & Status */}
            <div className="space-y-6">
              <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm space-y-6">
                <h2 className="text-lg font-semibold">Clean-up Details</h2>

                <div className="space-y-4">
                  <div className="flex items-center gap-3">
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center ${status === AppStatus.ANALYZING ? 'bg-indigo-100' : 'bg-green-100'}`}>
                      {status === AppStatus.ANALYZING ? <Loader2 className="w-4 h-4 animate-spin text-indigo-600" /> : <CheckCircle2 className="w-4 h-4 text-green-600" />}
                    </div>
                    <div>
                      <p className="font-medium text-sm">Pattern Detection</p>
                      <p className="text-xs text-slate-500">Gemini is identifying watermark signatures...</p>
                    </div>
                  </div>

                  {detection && (
                    <div className="p-4 bg-slate-50 rounded-xl border border-slate-200 space-y-2">
                      <div className="flex justify-between items-center">
                        <span className="text-xs font-medium text-slate-500 uppercase tracking-wider">Detection Result</span>
                        <span className="text-[10px] bg-indigo-100 text-indigo-700 px-2 py-0.5 rounded-full font-bold">
                          {Math.round(detection.confidence * 100)}% Match
                        </span>
                      </div>
                      <p className="text-sm text-slate-700 leading-relaxed">
                        <ScanSearch className="w-4 h-4 inline-block mr-1 text-slate-400" />
                        {detection.description}
                      </p>
                      <div className="flex items-center gap-2 pt-2 border-t border-slate-200 mt-2">
                        <div className="w-4 h-4 rounded border border-slate-300" style={{ backgroundColor: detection.backgroundColor }}></div>
                        <span className="text-xs text-slate-500">Patch Color: {detection.backgroundColor}</span>
                      </div>
                    </div>
                  )}

                  {(status === AppStatus.PROCESSING || status === AppStatus.COMPLETED) && (
                    <div className="space-y-2">
                      <div className="flex justify-between text-sm font-medium">
                        <span>{status === AppStatus.COMPLETED ? 'Process Complete' : 'Removing Watermarks...'}</span>
                        <span>{progress}%</span>
                      </div>
                      <div className="h-2 bg-slate-100 rounded-full overflow-hidden">
                        <div 
                          className="h-full bg-indigo-600 transition-all duration-300 ease-out"
                          style={{ width: `${progress}%` }}
                        />
                      </div>
                    </div>
                  )}
                </div>

                {status === AppStatus.READY_TO_PROCESS && (
                  <button 
                    onClick={startProcessing}
                    className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-4 rounded-xl shadow-lg shadow-indigo-200 transition-all flex items-center justify-center gap-2 group"
                  >
                    <MousePointer2 className="w-5 h-5 group-hover:translate-x-1 group-hover:-translate-y-1 transition-transform" />
                    Clean PDF Now
                  </button>
                )}

                {status === AppStatus.COMPLETED && (
                  <div className="space-y-3">
                    <button 
                      onClick={downloadResult}
                      className="w-full bg-green-600 hover:bg-green-700 text-white font-bold py-4 rounded-xl shadow-lg shadow-green-200 transition-all flex items-center justify-center gap-2"
                    >
                      <Download className="w-5 h-5" />
                      Download Cleaned PDF
                    </button>
                    <button 
                      onClick={reset}
                      className="w-full bg-white border border-slate-200 text-slate-600 font-semibold py-3 rounded-xl hover:bg-slate-50 transition-colors"
                    >
                      Process Another File
                    </button>
                  </div>
                )}
              </div>

              {/* Tips Section */}
              <div className="p-4 bg-amber-50 rounded-xl border border-amber-200">
                <h4 className="text-xs font-bold text-amber-800 uppercase mb-2">Pro Tip</h4>
                <p className="text-xs text-amber-700 leading-relaxed">
                  Our intelligent algorithm uses Gemini to find exact watermark boundaries and background colors, allowing for pixel-perfect patching while preserving text layers.
                </p>
              </div>
            </div>
          </div>
        )}
      </main>

      <footer className="mt-auto border-t border-slate-200 bg-white py-8">
        <div className="max-w-6xl mx-auto px-4 text-center text-slate-400 text-sm">
          <p>© 2024 PDF Watermark Remover Pro. Intelligent PDF processing simplified.</p>
        </div>
      </footer>
    </div>
  );
}

import { PDFDocument, rgb } from 'pdf-lib';

// Declare pdfjsLib globally since it's loaded in index.html
declare const pdfjsLib: any;

export async function getPdfThumbnail(file: File): Promise<{ dataUrl: string; width: number; height: number }> {
  const arrayBuffer = await file.arrayBuffer();
  const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
  const page = await pdf.getPage(1);
  const viewport = page.getViewport({ scale: 1.5 });

  const canvas = document.createElement('canvas');
  const context = canvas.getContext('2d')!;
  canvas.height = viewport.height;
  canvas.width = viewport.width;

  await page.render({ canvasContext: context, viewport }).promise;
  return {
    dataUrl: canvas.toDataURL('image/jpeg', 0.9),
    width: viewport.width,
    height: viewport.height
  };
}

