export async function getBottomRightCrop(file: File): Promise<{ base64: string; width: number; height: number }> {
  const arrayBuffer = await file.arrayBuffer();
  const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
  const page = await pdf.getPage(1);

  const viewport = page.getViewport({ scale: 2.0 });
  const canvas = document.createElement('canvas');
  const context = canvas.getContext('2d')!;

  const cropW = viewport.width * 0.4;
  const cropH = viewport.height * 0.4;
  canvas.width = cropW;
  canvas.height = cropH;

  context.translate(- (viewport.width - cropW), - (viewport.height - cropH));
  await page.render({ canvasContext: context, viewport }).promise;

  return {
    base64: canvas.toDataURL('image/jpeg', 0.95).split(',')[1],
    width: cropW,
    height: cropH
  };
}

export function hexToRgb(hex: string) {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result ? {
    r: parseInt(result[1], 16) / 255,
    g: parseInt(result[2], 16) / 255,
    b: parseInt(result[3], 16) / 255
  } : { r: 1, g: 1, b: 1 };
}

export async function removeWatermarkFromPdf(
  file: File, 
  detection: { x: number; y: number; width: number; height: number; backgroundColor: string },
  onProgress: (p: number) => void
): Promise<Uint8Array> {
  const existingPdfBytes = await file.arrayBuffer();
  const pdfDoc = await PDFDocument.load(existingPdfBytes);
  const pages = pdfDoc.getPages();
  const { r, g, b } = hexToRgb(detection.backgroundColor);

  for (let i = 0; i < pages.length; i++) {
    const page = pages[i];
    const { width, height } = page.getSize();

    // Mapping detection (0-100 of bottom-right 40% crop) to PDF coordinates
    const patchWidth = (detection.width / 100) * (width * 0.4);
    const patchHeight = (detection.height / 100) * (height * 0.4);

    // X: starts at 60% of page width
    const patchX = (width * 0.6) + (detection.x / 100) * (width * 0.4);

    // Y: 0 is bottom. The crop top is at height * 0.4.
    // detection.y 0 is top of crop, 100 is bottom of crop.
    const cropTopInPdf = height * 0.4;
    const patchY = cropTopInPdf - (detection.y / 100) * (height * 0.4) - patchHeight;

    page.drawRectangle({
      x: patchX,
      y: patchY,
      width: patchWidth,
      height: patchHeight,
      color: rgb(r, g, b),
      borderWidth: 0,
    });

    onProgress(Math.round(((i + 1) / pages.length) * 100));
  }

  return await pdfDoc.save();
}

import { GoogleGenAI, Type } from "@google/genai";
import { WatermarkDetectionResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export async function detectWatermark(imageBase64: string): Promise<WatermarkDetectionResult> {
  const model = 'gemini-3-flash-preview';

  const prompt = `
    Analyze the provided image, which is a crop of the bottom-right 40% of a PDF slide.
    1. Identify the exact bounding box (x, y, width, height) of the watermark, logo, or page number branding.
    2. Coordinates must be integers 0-100 relative to this crop.
    3. Determine the HEX background color specifically in the area surrounding the watermark. This is crucial for "seamless" restoration.
    4. Provide a high-confidence bounding box that covers the entire watermark area without cutting off edges.
    Return JSON only.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: {
      parts: [
        { inlineData: { mimeType: 'image/jpeg', data: imageBase64 } },
        { text: prompt }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          x: { type: Type.NUMBER },
          y: { type: Type.NUMBER },
          width: { type: Type.NUMBER },
          height: { type: Type.NUMBER },
          confidence: { type: Type.NUMBER },
          backgroundColor: { type: Type.STRING, description: "The sampled hex color of the background (e.g. #F5F5F5)" },
          description: { type: Type.STRING }
        },
        required: ["x", "y", "width", "height", "backgroundColor"]
      }
    }
  });

  try {
    const result = JSON.parse(response.text || '{}');
    return result as WatermarkDetectionResult;
  } catch (error) {
    console.error("Failed to parse Gemini response", error);
    throw new Error("Could not detect watermark. Please try another file or ensure it has a visible watermark in the bottom-right.");
  }
}

