import { PDFDocument, rgb } from 'pdf-lib';
import JSZip from 'jszip';

// Declare pdfjsLib globally since it's loaded in index.html
declare const pdfjsLib: any;

/**
 * Generates a full thumbnail for the first page.
 */
export async function getPdfThumbnail(file: File): Promise<{ dataUrl: string; width: number; height: number }> {
  const arrayBuffer = await file.arrayBuffer();
  const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
  const page = await pdf.getPage(1);
  const viewport = page.getViewport({ scale: 1.5 });

  const canvas = document.createElement('canvas');
  const context = canvas.getContext('2d')!;
  canvas.height = viewport.height;
  canvas.width = viewport.width;

  await page.render({ canvasContext: context, viewport }).promise;
  return {
    dataUrl: canvas.toDataURL('image/jpeg', 0.9),
    width: viewport.width,
    height: viewport.height
  };
}

/**
 * Gets a high-res crop of the bottom-right 40% of the first page for Gemini analysis.
 */
export async function getBottomRightCrop(file: File): Promise<{ base64: string; width: number; height: number }> {
  const arrayBuffer = await file.arrayBuffer();
  const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
  const page = await pdf.getPage(1);

  const viewport = page.getViewport({ scale: 2.0 });
  const canvas = document.createElement('canvas');
  const context = canvas.getContext('2d')!;

  const cropW = viewport.width * 0.4;
  const cropH = viewport.height * 0.4;
  canvas.width = cropW;
  canvas.height = cropH;

  context.translate(- (viewport.width - cropW), - (viewport.height - cropH));
  await page.render({ canvasContext: context, viewport }).promise;

  return {
    base64: canvas.toDataURL('image/jpeg', 0.95).split(',')[1],
    width: cropW,
    height: cropH
  };
}

/**
 * Samples the background color from a specific PDF page at a specific point.
 * Used for per-page "Smart Color Sampling".
 */
async function sampleColorFromPage(
  pdf: any,
  pageNum: number,
  xPercent: number,
  yPercent: number
): Promise<{ r: number, g: number, b: number }> {
  const page = await pdf.getPage(pageNum);
  const scale = 1.0;
  const viewport = page.getViewport({ scale });

  const canvas = document.createElement('canvas');
  const context = canvas.getContext('2d')!;
  canvas.width = 1;
  canvas.height = 1;

  const sampleX = (xPercent / 100) * viewport.width;
  const sampleY = (yPercent / 100) * viewport.height;

  context.translate(-sampleX, -sampleY);
  await page.render({ canvasContext: context, viewport }).promise;

  const pixel = context.getImageData(0, 0, 1, 1).data;
  return {
    r: pixel[0] / 255,
    g: pixel[1] / 255,
    b: pixel[2] / 255
  };
}

export function hexToRgb(hex: string) {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result ? {
    r: parseInt(result[1], 16) / 255,
    g: parseInt(result[2], 16) / 255,
    b: parseInt(result[3], 16) / 255
  } : { r: 1, g: 1, b: 1 };
}

/**
 * Removes watermark from PDF with intelligent per-page color detection.
 */
export async function removeWatermarkFromPdf(
  file: File, 
  detection: { x: number; y: number; width: number; height: number; backgroundColor: string },
  onProgress: (p: number) => void
): Promise<Uint8Array> {
  const arrayBuffer = await file.arrayBuffer();

  const pdfDoc = await PDFDocument.load(arrayBuffer);
  const pages = pdfDoc.getPages();
  const pdfJsDoc = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;

  for (let i = 0; i < pages.length; i++) {
    const page = pages[i];
    const { width, height } = page.getSize();

    const relativeXInPage = 60 + (detection.x * 0.4);
    const relativeYInPage = 60 + (detection.y * 0.4);

    let pageColor;
    try {
      pageColor = await sampleColorFromPage(
        pdfJsDoc, 
        i + 1, 
        Math.max(0, relativeXInPage - 2), 
        relativeYInPage + (detection.height * 0.2)
      );
    } catch (e) {
      console.warn("Color sampling failed for page", i + 1, "falling back to base color.");
      pageColor = hexToRgb(detection.backgroundColor);
    }

    const patchWidth = (detection.width / 100) * (width * 0.4);
    const patchHeight = (detection.height / 100) * (height * 0.4);

    const patchX = (width * 0.6) + (detection.x / 100) * (width * 0.4);
    const cropTopInPdf = height * 0.4;
    const patchY = cropTopInPdf - (detection.y / 100) * (height * 0.4) - patchHeight;

    page.drawRectangle({
      x: patchX,
      y: patchY,
      width: patchWidth,
      height: patchHeight,
      color: rgb(pageColor.r, pageColor.g, pageColor.b),
      borderWidth: 0,
    });

    onProgress(Math.round(((i + 1) / pages.length) * 100));
  }

  return await pdfDoc.save();
}

/**
 * Converts PDF pages into HD images and bundles them into a ZIP file.
 */
export async function convertPdfToImagesZip(
  pdfBytes: Uint8Array,
  onProgress: (p: number) => void
): Promise<Blob> {
  const pdf = await pdfjsLib.getDocument({ data: pdfBytes }).promise;
  const numPages = pdf.numPages;
  const zip = new JSZip();
  const scale = 3.0; // High definition scale

  for (let i = 1; i <= numPages; i++) {
    const page = await pdf.getPage(i);
    const viewport = page.getViewport({ scale });

    const canvas = document.createElement('canvas');
    const context = canvas.getContext('2d')!;
    canvas.height = viewport.height;
    canvas.width = viewport.width;

    await page.render({ canvasContext: context, viewport }).promise;

    // Convert canvas to blob (JPEG for smaller file size, PNG for best quality)
    const imageBlob = await new Promise<Blob>((resolve) => {
      canvas.toBlob((blob) => resolve(blob!), 'image/png');
    });

    zip.file(`slide_${i.toString().padStart(3, '0')}.png`, imageBlob);
    onProgress(Math.round((i / numPages) * 100));
  }

  return await zip.generateAsync({ type: 'blob' });
}

import React, { useState, useRef } from 'react';
import { 
  FileUp, 
  Trash2, 
  CheckCircle2, 
  Download, 
  Zap, 
  Loader2, 
  AlertCircle,
  FileText,
  MousePointer2,
  ScanSearch,
  Pipette,
  History,
  Sparkles,
  Image as ImageIcon,
  Package
} from 'lucide-react';
import { AppStatus, WatermarkDetectionResult } from './types';
import { 
  getPdfThumbnail, 
  getBottomRightCrop, 
  removeWatermarkFromPdf, 
  convertPdfToImagesZip 
} from './services/pdfService';
import { detectWatermark } from './services/geminiService';

export default function App() {
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [file, setFile] = useState<File | null>(null);
  const [thumbnail, setThumbnail] = useState<string | null>(null);
  const [detection, setDetection] = useState<WatermarkDetectionResult | null>(null);
  const [progress, setProgress] = useState(0);
  const [error, setError] = useState<string | null>(null);
  const [processedPdf, setProcessedPdf] = useState<Uint8Array | null>(null);
  const [isZipping, setIsZipping] = useState(false);
  const [zipProgress, setZipProgress] = useState(0);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (!selectedFile || selectedFile.type !== 'application/pdf') {
      setError("请选择有效的 PDF 文件。");
      return;
    }
    reset();
    setFile(selectedFile);
    setStatus(AppStatus.UPLOADING);

    try {
      const { dataUrl } = await getPdfThumbnail(selectedFile);
      setThumbnail(dataUrl);
      setStatus(AppStatus.ANALYZING);

      const { base64 } = await getBottomRightCrop(selectedFile);
      const result = await detectWatermark(base64);

      if (result.width <= 0 || result.height <= 0) {
        throw new Error("AI 未能在右下角检测到明显的水印或标识。");
      }

      setDetection(result);
      setStatus(AppStatus.READY_TO_PROCESS);
    } catch (err: any) {
      setError(err.message || "分析过程中出现错误。");
      setStatus(AppStatus.IDLE);
    }
  };

  const startProcessing = async () => {
    if (!file || !detection) return;
    setStatus(AppStatus.PROCESSING);
    setProgress(0);

    try {
      const result = await removeWatermarkFromPdf(file, detection, (p) => setProgress(p));
      setProcessedPdf(result);
      setStatus(AppStatus.COMPLETED);
    } catch (err: any) {
      setError(err.message || "PDF 处理失败。");
      setStatus(AppStatus.READY_TO_PROCESS);
    }
  };

  const downloadResult = () => {
    if (!processedPdf || !file) return;
    const blob = new Blob([processedPdf], { type: 'application/pdf' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `cleaned_${file.name}`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleConvertToZip = async () => {
    if (!processedPdf || !file) return;
    setIsZipping(true);
    setZipProgress(0);
    try {
      const zipBlob = await convertPdfToImagesZip(processedPdf, (p) => setZipProgress(p));
      const url = URL.createObjectURL(zipBlob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `${file.name.replace('.pdf', '')}_HD_Images.zip`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
    } catch (err: any) {
      setError("导出图片包失败。");
    } finally {
      setIsZipping(false);
    }
  };

  const reset = () => {
    setFile(null);
    setThumbnail(null);
    setDetection(null);
    setProcessedPdf(null);
    setProgress(0);
    setError(null);
    setStatus(AppStatus.IDLE);
    setIsZipping(false);
    setZipProgress(0);
  };

  const updateColor = (color: string) => {
    if (detection) {
      setDetection({ ...detection, backgroundColor: color });
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 font-sans text-slate-900 selection:bg-indigo-100 selection:text-indigo-900">
      <header className="bg-white/80 backdrop-blur-md border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-6xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2.5 rounded-xl shadow-lg shadow-indigo-200">
              <Zap className="text-white w-5 h-5 fill-current" />
            </div>
            <h1 className="text-xl font-extrabold tracking-tight bg-gradient-to-br from-indigo-700 via-indigo-600 to-violet-600 bg-clip-text text-transparent">
              PDF 智能助手
            </h1>
          </div>
          {status !== AppStatus.IDLE && (
            <button 
              onClick={reset}
              className="text-slate-400 hover:text-red-500 transition-all p-2 rounded-xl hover:bg-red-50 active:scale-95"
              title="重置"
            >
              <Trash2 className="w-5 h-5" />
            </button>
          )}
        </div>
      </header>

      <main className="max-w-5xl mx-auto px-4 py-12">
        {error && (
          <div className="mb-8 p-4 bg-red-50 border border-red-200 rounded-2xl flex items-center gap-3 text-red-700 animate-in fade-in slide-in-from-top-4 duration-300">
            <AlertCircle className="w-5 h-5 flex-shrink-0" />
            <p className="font-semibold">{error}</p>
