            <div className="mt-16 grid grid-cols-1 md:grid-cols-3 gap-8 w-full max-w-4xl">
              {[
                { icon: Sparkles, title: "智能吸色", desc: "自动检测每页背景颜色" },
                { icon: Layers, title: "多级采样", desc: "1x 到 4x 自定义导出分辨率" },
