              <div className="relative aspect-[4/3] bg-white border-2 border-slate-100 rounded-[2.5rem] shadow-2xl shadow-slate-300/50 overflow-hidden ring-1 ring-slate-900/5">
                {thumbnail ? (
                  <>
                    <img src={thumbnail} className="w-full h-full object-contain" alt="PDF Preview" />
                    {detection && (
                      <div 
                        className="absolute border-[4px] border-indigo-500/80 bg-indigo-500/5 z-10 transition-all duration-700 ease-out shadow-[0_0_20px_rgba(79,70,229,0.3)]"
                        style={{
                          left: `${60 + (detection.x * 0.4)}%`,
                          top: `${60 + (detection.y * 0.4)}%`,
                          width: `${detection.width * 0.4}%`,
                          height: `${detection.height * 0.4}%`,
                        }}
                      >
                        <div className="absolute -top-9 left-0 bg-indigo-600 text-white text-[12px] px-3 py-1.5 rounded-xl shadow-xl font-black whitespace-nowrap flex items-center gap-2 animate-bounce-short">
                          <ScanSearch className="w-3.5 h-3.5" />
                          已锁定水印区域
                        </div>
                      </div>
                    )}
                    {(status === AppStatus.PROCESSING || isZipping) && (
                      <div className="absolute inset-0 bg-white/40 backdrop-blur-[3px] z-20 flex items-center justify-center transition-all duration-500">
                        <div className="bg-white/95 p-10 rounded-[3rem] shadow-[0_32px_64px_-12px_rgba(0,0,0,0.14)] flex flex-col items-center gap-6 border border-slate-100">
                          <div className="relative">
                             <div className="absolute inset-0 bg-indigo-500/20 blur-2xl rounded-full animate-pulse" />
                             <Loader2 className="w-16 h-16 text-indigo-600 animate-spin relative" />
                          </div>
                          <div className="text-center">
                            <p className="text-2xl font-black text-slate-800 tracking-tight">
                              {isZipping ? '正在导出高清图片...' : '智能去水印中...'}
                            </p>
                            <p className="text-slate-500 mt-1 font-medium italic">
                              {isZipping ? `正在渲染高清图像 (${selectedScale}x 采样)` : '正在逐页执行智能吸色覆盖'}
                            </p>
                          </div>
                        </div>
                      </div>
                    )}
                  </>
                ) : (
                  <div className="w-full h-full flex items-center justify-center bg-slate-50">
                    <Loader2 className="w-12 h-12 animate-spin text-indigo-300" />
                  </div>
                )}
              </div>
            </div>

            {/* Right: Controls Panel */}
            <div className="lg:col-span-4 space-y-6">
              <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-2xl shadow-slate-200/60 space-y-8">
                <div>
                  <h2 className="text-2xl font-black text-slate-800 mb-2 tracking-tight">处理配置</h2>
                  <p className="text-slate-400 font-medium text-sm">选择输出质量与参数</p>
                </div>

                <div className="space-y-5">
                  {/* Status Steps */}
                  <div className="p-5 bg-indigo-50/50 rounded-3xl border border-indigo-100/50 flex items-center gap-5 transition-all hover:bg-indigo-50">
                    <div className={`w-12 h-12 rounded-2xl flex items-center justify-center shadow-sm ${status === AppStatus.ANALYZING ? 'bg-indigo-600 text-white animate-pulse' : 'bg-green-100 text-green-600'}`}>
                      {status === AppStatus.ANALYZING ? <Loader2 className="w-6 h-6 animate-spin" /> : <CheckCircle2 className="w-6 h-6" />}
                    </div>
                    <div>
                      <p className="font-black text-slate-800">智能感知引擎</p>
                      <p className="text-xs text-indigo-600/70 font-bold uppercase tracking-widest mt-0.5">
                        {status === AppStatus.ANALYZING ? '分析中...' : '检测就绪'}
                      </p>
                    </div>
                  </div>

                  {/* Resolution Selector */}
                  <div className="space-y-3">
                    <label className="text-xs font-black text-slate-400 uppercase tracking-[0.2em] ml-2">导出采样率 (图片包专用)</label>
                    <div className="grid grid-cols-2 gap-2">
                      {EXPORT_SCALES.map((scale) => (
                        <button
                          key={scale.value}
                          onClick={() => setSelectedScale(scale.value)}
                          className={`flex flex-col items-center p-3 rounded-2xl border-2 transition-all ${
                            selectedScale === scale.value 
                              ? 'border-indigo-600 bg-indigo-50 text-indigo-700' 
                              : 'border-slate-100 hover:border-slate-200 bg-white text-slate-600'
                          }`}
                        >
                          <span className="text-sm font-black">{scale.label}</span>
                          <span className="text-[9px] font-bold opacity-70 mt-0.5">{scale.desc}</span>
                        </button>
                      ))}
                    </div>
                  </div>

                  {detection && (
                    <div className="p-6 bg-slate-50 rounded-[2rem] border border-slate-200 space-y-4 shadow-inner">
                      <div className="flex justify-between items-center">
                        <span className="text-xs font-black text-slate-400 uppercase tracking-[0.2em]">自动采样基色</span>
                        <Pipette className="w-4 h-4 text-indigo-500" />
                      </div>
                      <div className="flex items-center gap-4">
                        <div 
                          className="w-12 h-12 rounded-xl shadow-md ring-4 ring-white" 
                          style={{ backgroundColor: detection.backgroundColor }}
                        />
                        <p className="text-sm font-black text-slate-700 font-mono">{detection.backgroundColor.toUpperCase()}</p>
                      </div>
                    </div>
                  )}

                  {(status === AppStatus.PROCESSING || isZipping) && (
                    <div className="p-6 bg-indigo-600 rounded-[2rem] shadow-lg shadow-indigo-200 space-y-4">
                      <div className="flex justify-between text-sm font-black text-white italic">
                        <span>{isZipping ? 'HD 像素渲染中' : '重构 PDF 层'}</span>
                        <span>{isZipping ? zipProgress : progress}%</span>
                      </div>
                      <div className="h-2.5 bg-white/20 rounded-full overflow-hidden">
                        <div 
                          className="h-full bg-white rounded-full transition-all duration-300"
                          style={{ width: `${isZipping ? zipProgress : progress}%` }}
                        />
                      </div>
                    </div>
                  )}
                </div>

                {status === AppStatus.READY_TO_PROCESS && (
                  <button 
                    onClick={startProcessing}
                    className="w-full bg-slate-900 hover:bg-black text-white font-black py-6 rounded-3xl shadow-2xl shadow-slate-300 transition-all active:scale-[0.97] flex items-center justify-center gap-4 group"
                  >
                    <Zap className="w-6 h-6 text-indigo-400" />
                    <span className="text-lg">执行 智能去水印</span>
                  </button>
                )}

                {status === AppStatus.COMPLETED && (
                  <div className="space-y-4">
                    <button 
                      onClick={downloadResult}
                      className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-black py-5 rounded-3xl shadow-xl shadow-indigo-100 transition-all flex items-center justify-center gap-4 active:scale-95"
                    >
                      <Download className="w-5 h-5" />
                      <span className="text-md">下载已去水印 PDF</span>
                    </button>

                    <button 
                      onClick={handleConvertToZip}
                      disabled={isZipping}
                      className="w-full bg-emerald-600 hover:bg-emerald-700 text-white font-black py-5 rounded-3xl shadow-xl shadow-emerald-100 transition-all flex items-center justify-center gap-4 active:scale-95 disabled:opacity-50"
                    >
                      {isZipping ? <Loader2 className="w-5 h-5 animate-spin" /> : <Package className="w-5 h-5" />}
                      <span className="text-md">导出高清图片包 (ZIP)</span>
                    </button>

                    <button 
                      onClick={reset}
                      className="w-full bg-white border-2 border-slate-100 text-slate-500 font-black py-4 rounded-3xl hover:bg-slate-50 transition-all flex items-center justify-center gap-3 active:scale-[0.98]"
                    >
                      <History className="w-4 h-4" />
                      处理另一个文件
                    </button>
                  </div>
                )}
              </div>

              {/* Technical Detail Card */}
              <div className="p-6 bg-white rounded-[2.5rem] border border-slate-100 flex gap-5 shadow-sm">
                <div className="w-12 h-12 rounded-2xl bg-amber-50 flex items-center justify-center flex-shrink-0">
                  <Sparkles className="w-6 h-6 text-amber-500" />
                </div>
                <div>
                  <h4 className="text-md font-black text-slate-800 mb-1">采样率说明</h4>
                  <p className="text-xs text-slate-400 font-medium leading-relaxed">
                    采样率越高（如 4x），图片越清晰，但文件体积和处理时间也会相应增加。
                  </p>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>

      <footer className="mt-auto border-t border-slate-100 bg-white py-12">
        <div className="max-w-6xl mx-auto px-4 text-center">
          <p className="text-slate-300 text-sm font-black tracking-widest uppercase">
            Powered by Gemini 2.5 Vision & Custom Sampling Engine
          </p>
        </div>
